To display the number of seats booked by the user in the "My Rides" tab, I will calculate the booked seats for each ride based on the bookings list and display it within the status badge.

Here are the changes:

1.  **`screens/MyRides.tsx`**:
    *   Find the specific `booking` object for the current ride and user.
    *   Extract the `seats` count.
    *   Update the status badge to show the seat count next to "CONFIRMED" (e.g., "CONFIRMED • 2 seats").

# Updated files:

## screens/MyRides.tsx

Update the ride status badge to include the number of booked seats.

```tsx
<change>
<file>screens/MyRides.tsx</file>
<description>Display booked seat count on ride card badge</description>
<content><![CDATA[
import React, { useState } from 'react';
import { useApp } from '../store/AppContext';
import RideCard from '../components/RideCard';
import { Calendar, History } from 'lucide-react';

const MyRides = () => {
  const { state, t } = useApp();
  const [activeTab, setActiveTab] = useState<'upcoming' | 'history'>('upcoming');

  // Filter rides where user is driver OR user has a confirmed booking
  const bookedRideIds = state.bookings
    .filter(b => b.passengerId === state.user?.id)
    .map(b => b.rideId);

  const myRides = state.rides.filter(ride => 
    ride.driverId === state.user?.id || bookedRideIds.includes(ride.id)
  );

  const displayedRides = myRides.filter(ride => {
    const isFuture = new Date(ride.departureTime) > new Date();
    return activeTab === 'upcoming' ? isFuture : !isFuture;
  });

  return (
    <div className="pt-6 px-4 min-h-full bg-gray-50 pb-6">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">{t('rides.title')}</h1>

      <div className="flex bg-gray-200 p-1 rounded-xl mb-6">
        <button 
          onClick={() => setActiveTab('upcoming')}
          className={`flex-1 flex items-center justify-center py-2 text-sm font-semibold rounded-lg transition-all ${
            activeTab === 'upcoming' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500'
          }`}
        >
          <Calendar size={16} className="me-2" />
          {t('rides.tab.upcoming')}
        </button>
        <button 
          onClick={() => setActiveTab('history')}
          className={`flex-1 flex items-center justify-center py-2 text-sm font-semibold rounded-lg transition-all ${
            activeTab === 'history' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500'
          }`}
        >
          <History size={16} className="me-2" />
          {t('rides.tab.history')}
        </button>
      </div>

      <div className="space-y-4">
        {displayedRides.length > 0 ? (
          displayedRides.map(ride => {
            const isDriver = ride.driverId === state.user?.id;
            const booking = state.bookings.find(b => b.rideId === ride.id && b.passengerId === state.user?.id);
            const bookedSeats = booking ? booking.seats : 0;

            return (
              <div key={ride.id} className="relative">
                <div className={`absolute top-4 end-4 text-[10px] font-bold px-2 py-1 rounded-full z-10 shadow-sm border ${
                  isDriver 
                    ? 'bg-indigo-100 text-indigo-700 border-indigo-200' 
                    : 'bg-green-100 text-green-700 border-green-200'
                }`}>
                  {isDriver 
                    ? 'DRIVER' 
                    : `${t('rides.confirmed')} • ${bookedSeats} ${t('ride.seats')}`
                  }
                </div>
                <RideCard ride={ride} />
              </div>
            );
          })
        ) : (
          <div className="text-center py-12">
            <div className="w-16 h-16 bg-gray-200 rounded-full flex items-center justify-center mx-auto mb-4">
              {activeTab === 'upcoming' ? <Calendar className="text-gray-400" /> : <History className="text-gray-400" />}
            </div>
            <p className="text-gray-500 font-medium">{t('rides.empty_history')}</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default MyRides;
]]></content>
</change>
